create table clients (id uuid primary key, phone varchar(32) not null unique, created_at timestamptz not null default now());
create table sms_challenges (id uuid primary key, phone varchar(32) not null, code_hash varchar(255) not null, expires_at timestamptz not null, consumed_at timestamptz, created_at timestamptz not null default now());
create table auth_sessions (id uuid primary key, client_id uuid not null references clients(id), token_hash varchar(255) not null unique, expires_at timestamptz not null, revoked_at timestamptz, created_at timestamptz not null default now());
create table chefs (id uuid primary key, name varchar(160) not null, bio text, photo_url text);
create table chef_specializations (chef_id uuid not null references chefs(id) on delete cascade, specialization varchar(120) not null, primary key (chef_id, specialization));
create table programs (id uuid primary key, title varchar(200) not null, description text not null, difficulty varchar(32) not null check (difficulty in ('BEGINNER','INTERMEDIATE','ADVANCED')), duration_minutes integer not null check (duration_minutes > 0), price_cents integer not null check (price_cents >= 0));
create table program_menu_items (id uuid primary key, program_id uuid not null references programs(id) on delete cascade, name varchar(180) not null, position integer not null check (position >= 0));
create table slots (id uuid primary key, program_id uuid not null references programs(id), chef_id uuid not null references chefs(id), starts_at timestamptz not null, ends_at timestamptz not null, capacity integer not null check (capacity >= 0), booked_seats integer not null default 0 check (booked_seats >= 0), status varchar(32) not null check (status in ('SCHEDULED','CANCELLED_BY_STUDIO')), check (ends_at > starts_at), check (booked_seats <= capacity));
create index idx_slots_starts_at on slots(starts_at);
create index idx_slots_status_starts_at on slots(status, starts_at);
create table rental_items (id uuid primary key, name varchar(160) not null, description text, price_cents integer not null check (price_cents >= 0), stock integer not null check (stock >= 0), active boolean not null default true);
create table allergens (id uuid primary key, code varchar(64) not null unique, name varchar(160) not null);
create table bookings (id uuid primary key, client_id uuid not null references clients(id), slot_id uuid not null references slots(id), status varchar(32) not null check (status in ('ACTIVE','CANCELLED_BY_CLIENT','CANCELLED_BY_STUDIO','COMPLETED','NO_SHOW')), payment_status varchar(32) not null check (payment_status in ('NOT_REQUIRED','PENDING','PAID','REFUNDED')), total_price_cents integer not null check (total_price_cents >= 0), attended boolean not null default false, created_at timestamptz not null default now(), cancelled_at timestamptz);
create index idx_bookings_client_created_at on bookings(client_id, created_at desc);
create index idx_bookings_slot on bookings(slot_id);
create table booking_rental_items (booking_id uuid not null references bookings(id) on delete cascade, rental_item_id uuid not null references rental_items(id), quantity integer not null check (quantity > 0), primary key (booking_id, rental_item_id));
create table booking_allergens (booking_id uuid not null references bookings(id) on delete cascade, allergen_id uuid not null references allergens(id), primary key (booking_id, allergen_id));
create table client_allergens (client_id uuid not null references clients(id) on delete cascade, allergen_id uuid not null references allergens(id), primary key (client_id, allergen_id));
create table ratings (id uuid primary key, booking_id uuid not null unique references bookings(id) on delete cascade, chef_id uuid not null references chefs(id), client_id uuid not null references clients(id), stars integer not null check (stars between 1 and 5), comment text, created_at timestamptz not null default now());
create table idempotency_keys (id uuid primary key, key_value varchar(120) not null unique, client_id uuid references clients(id), response_status integer, response_body text, created_at timestamptz not null default now());
